package pe.edu.utp.tmo.controller; import jakarta.validation.Valid; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import pe.edu.utp.tmo.dto.request.LoginRequest; import pe.edu.utp.tmo.dto.response.AuthResponse; import pe.edu.utp.tmo.service.AuthService; @RestController @RequestMapping("/api/auth") public class AuthController{ private final AuthService s; public AuthController(AuthService s){this.s=s;} @PostMapping("/login") ResponseEntity<AuthResponse> login(@Valid @RequestBody LoginRequest r){return ResponseEntity.ok(s.login(r));}}